CREATE TABLE IF NOT EXISTS public.feature_flags ("key" text NOT NULL, "enabled" boolean DEFAULT true NOT NULL, "description" text, "updated_by" uuid, "updated_at" timestamp with time zone DEFAULT now() NOT NULL, "flag_key" text);
CREATE TABLE IF NOT EXISTS public.form_assignments ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "form_id" uuid NOT NULL, "user_id" uuid, "opd_id" uuid, "status" text DEFAULT 'pending'::text NOT NULL, "assigned_by" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL, "version_number" integer DEFAULT 1 NOT NULL, "due_at" timestamp with time zone, "assigned_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.form_fields ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "form_id" uuid NOT NULL, "kode" text NOT NULL, "label" text NOT NULL, "tipe" text DEFAULT 'text'::text NOT NULL, "urutan" integer DEFAULT 0 NOT NULL, "required" boolean DEFAULT false NOT NULL, "options" jsonb DEFAULT '[]'::jsonb, "help" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "visible_if" jsonb, "placeholder" text, "help_text" text, "validation" jsonb DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS public.form_submission_comment ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "submission_id" uuid NOT NULL, "oleh" uuid, "pesan" text NOT NULL, "internal_only" boolean DEFAULT false NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.form_submission_files ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "submission_id" uuid NOT NULL, "field_kode" text, "storage_path" text NOT NULL, "provider" text DEFAULT 'supabase'::text NOT NULL, "mime" text, "size_bytes" bigint, "cleanup_status" text DEFAULT 'ok'::text, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL, "uploaded_by" uuid, "finalized_at" timestamp with time zone);
CREATE TABLE IF NOT EXISTS public.form_submission_versions ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "submission_id" uuid NOT NULL, "version" integer DEFAULT 1 NOT NULL, "data" jsonb DEFAULT '{}'::jsonb NOT NULL, "files" jsonb DEFAULT '[]'::jsonb, "created_by" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.form_submissions ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "form_id" uuid NOT NULL, "user_id" uuid, "opd_id" uuid, "data" jsonb DEFAULT '{}'::jsonb NOT NULL, "status" text DEFAULT 'draft'::text NOT NULL, "assignment_id" uuid, "submitted_at" timestamp with time zone, "reviewed_at" timestamp with time zone, "reviewed_by" uuid, "version_number" integer DEFAULT 1 NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL, "schema_version_snapshot" jsonb, "review_note" text);
CREATE TABLE IF NOT EXISTS public.form_targets ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "form_id" uuid NOT NULL, "target_type" text NOT NULL, "target_id" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "target_value" text);
CREATE TABLE IF NOT EXISTS public.forms ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "judul" text NOT NULL, "deskripsi" text, "opd_pemilik_id" uuid, "status" text DEFAULT 'draft'::text NOT NULL, "schema_snapshot" jsonb DEFAULT '{}'::jsonb, "slug" text, "is_public" boolean DEFAULT false NOT NULL, "published_at" timestamp with time zone, "created_by" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL, "deadline" timestamp with time zone, "allow_multiple_submit" boolean DEFAULT false NOT NULL, "published_by" uuid, "archived_at" timestamp with time zone);
CREATE TABLE IF NOT EXISTS public.geofence_audit ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "user_id" uuid, "opd_id" uuid, "lat" numeric, "lng" numeric, "dist_m" numeric, "radius_m" numeric, "valid" boolean, "reason" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.hari_libur ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "tanggal" date NOT NULL, "nama" text NOT NULL, "jenis" text DEFAULT 'nasional'::text NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "nasional" boolean DEFAULT true NOT NULL, "catatan" text);
CREATE TABLE IF NOT EXISTS public.ikm_responses ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "survey_id" uuid NOT NULL, "permohonan_id" uuid, "user_id" uuid, "u1" integer, "u2" integer, "u3" integer, "u4" integer, "u5" integer, "u6" integer, "u7" integer, "u8" integer, "u9" integer, "saran" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.ikm_surveys ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "opd_id" uuid, "layanan_id" uuid, "judul" text NOT NULL, "aktif" boolean DEFAULT true NOT NULL, "mulai" date, "selesai" date, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL, "periode" text, "created_by" uuid);
DO $$ BEGIN CREATE TYPE job_status AS ENUM ('pending','running','done','failed','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE TABLE IF NOT EXISTS public.job_queue ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "job_type" text NOT NULL, "payload" jsonb DEFAULT '{}'::jsonb NOT NULL, "status" job_status DEFAULT 'pending'::job_status NOT NULL, "attempts" integer DEFAULT 0 NOT NULL, "max_attempts" integer DEFAULT 3 NOT NULL, "scheduled_at" timestamp with time zone DEFAULT now() NOT NULL, "started_at" timestamp with time zone, "finished_at" timestamp with time zone, "error" text, "result" jsonb, "created_by" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.kantor_qr ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "opd_id" uuid NOT NULL, "token" text NOT NULL, "label" text, "lokasi" text, "lat" numeric, "lng" numeric, "radius_m" integer DEFAULT 100 NOT NULL, "aktif" boolean DEFAULT true NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.kategori_layanan ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "nama" text NOT NULL, "slug" text NOT NULL, "sla_hari" integer DEFAULT 7 NOT NULL, "deskripsi" text, "aktif" boolean DEFAULT true NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.laporan_masyarakat ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "nama" text NOT NULL, "nik" text, "email" text NOT NULL, "no_hp" text, "kategori" text NOT NULL, "lokasi" text, "uraian" text NOT NULL, "status" text DEFAULT 'baru'::text NOT NULL, "opd_id" uuid, "tindak_lanjut" text, "ditangani_oleh" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.layanan_publik ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "judul" text NOT NULL, "slug" text NOT NULL, "deskripsi" text, "ikon" text, "opd_id" uuid, "persyaratan" text, "alur" text, "aktif" boolean DEFAULT true NOT NULL, "urutan" integer DEFAULT 0 NOT NULL, "sla_hari" integer DEFAULT 14 NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.leave_balances ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "user_id" uuid NOT NULL, "tahun" integer NOT NULL, "jenis" text NOT NULL, "kuota" integer DEFAULT 0 NOT NULL, "terpakai" integer DEFAULT 0 NOT NULL, "catatan" text, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.lokasi_gedung ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "nama" text NOT NULL, "alamat" text, "opd_id" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.lokasi_lantai ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "gedung_id" uuid NOT NULL, "nama" text NOT NULL, "urutan" integer DEFAULT 0 NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.lokasi_ruangan ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "lantai_id" uuid NOT NULL, "nama" text NOT NULL, "kode" text, "pic_user_id" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.nomor_surat_issued ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "nomor" text NOT NULL, "tahun" integer NOT NULL, "opd_id" uuid, "permohonan_id" uuid, "issued_at" timestamp with time zone DEFAULT now() NOT NULL, "issued_by" uuid, "created_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE IF NOT EXISTS public.nomor_surat_sequence ("id" uuid DEFAULT gen_random_uuid() NOT NULL, "opd_id" uuid, "tahun" integer NOT NULL, "last_number" integer DEFAULT 0 NOT NULL, "created_at" timestamp with time zone DEFAULT now() NOT NULL, "updated_at" timestamp with time zone DEFAULT now() NOT NULL);